"use strict";$(document).ready(function(){var e=$('[data-editor-target="editor"]').get(0);if(e)new Quill(e,{placeholder:"Compose an epic...",theme:"snow"});$('[data-alert-target="#alertMessage"]').click(function(e){e.preventDefault();const t=Swal.mixin({customClass:{confirmButton:"btn btn-success m-1",cancelButton:"btn btn-danger m-1"},buttonsStyling:!1});t.fire({title:"Are you sure?",text:"You want to sent this Proposal!",icon:"warning",showCancelButton:!0,confirmButtonText:"Yes, sent it!",cancelButtonText:"No, cancel!",reverseButtons:!0}).then(e=>{e.value?t.fire("Sent!","Proposal sent successfully.","success"):e.dismiss===Swal.DismissReason.cancel&&t.fire("Cancelled","Your imaginary file is safe :)","error")})});var a=document.getElementById("startDate"),n=document.getElementById("endDate"),r=document.getElementById("payslipDate");a&&new Datepicker(a,{clearBtn:!0,allowOneSidedRange:!0}),n&&new Datepicker(n,{clearBtn:!0,allowOneSidedRange:!0}),r&&new Datepicker(r,{clearBtn:!0,allowOneSidedRange:!0})});
